import{_ as r,o,c as a,ae as i}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"Branch Partners with Google on ICM for Enhanced Mobile Measurement","description":"","frontmatter":{"title":"Branch Partners with Google on ICM for Enhanced Mobile Measurement","slug":"branch-google-icm-for-enhanced-mobile-measurement"},"headers":[],"relativePath":"account-hub/branch-google-icm-for-enhanced-mobile-measurement.md","filePath":"account-hub/branch-google-icm-for-enhanced-mobile-measurement.md"}'),t={name:"account-hub/branch-google-icm-for-enhanced-mobile-measurement.md"};function n(s,e,l,c,p,g){return o(),a("div",null,[...e[0]||(e[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch is excited to announce our upcoming support for Google&#39;s <a href="https://support.google.com/google-ads/answer/16203286?hl=en" target="_blank" rel="noreferrer">Integrated Conversion Measurement (ICM)</a>, a new solution designed to enhance your mobile campaign performance and provide more comprehensive reporting across iOS and Android.</p><p>As an official Google <a href="https://support.google.com/google-ads/answer/12961402" target="_blank" rel="noreferrer">App Attribution Partner</a>, Branch is supporting ICM to empower marketers and developers with improved insights, while prioritizing user privacy.</p><h2 id="what-is-google-icm" tabindex="-1">What is Google ICM? <a class="header-anchor" href="#what-is-google-icm" aria-label="Permalink to &quot;What is Google ICM?&quot;">​</a></h2><p>Google&#39;s ICM is a forward-thinking solution designed to provide more reliable and privacy-centric mobile app conversion measurement.</p><p>By leveraging techniques like <a href="https://support.google.com/google-ads/answer/12119136" target="_blank" rel="noreferrer">on-device measurement</a>, ICM aims to improve reporting accuracy for iOS and Android campaigns, especially in light of evolving privacy landscapes.</p><p>On-device measurement is a privacy-preserving technique where conversion data is processed directly on the user&#39;s device rather than being sent to a centralized server for aggregation before attribution. This method enhances user privacy while still allowing for accurate campaign measurement.</p><h2 id="key-benefits" tabindex="-1">Key benefits <a class="header-anchor" href="#key-benefits" aria-label="Permalink to &quot;Key benefits&quot;">​</a></h2><p>Below are some of the key benefits you can expect from using Google’s ICM with Branch:</p><ul><li><p><strong>Enhanced reporting across iOS &amp; Android</strong>: Get real-time and event-level reporting of your campaign performance.</p><ul><li>On iOS, gain improved reporting for app conversions from iOS 14+ users.</li><li>On Android, benefit from better reporting for app conversions from the European Economic Area (EEA) or when a user opts out of device-level permissions.</li></ul></li><li><p><strong>Privacy-preserving techniques</strong>: ICM utilizes privacy-preserving technologies, ensuring no identifiable information leaves a user&#39;s device or is disclosed externally, including to Google.</p></li><li><p><strong>Seamless integration</strong>: As a Google App Attribution Partner, Branch directly integrates with Google ICM, enhancing reporting for advertisers whether you&#39;re using our SDK or server-to-server integrations.</p></li></ul><h2 id="getting-started" tabindex="-1">Getting started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting started&quot;">​</a></h2><p>Use the information in this section to understand the process for getting Google ICM data flowing for your app campaigns.</p><h3 id="ios" tabindex="-1">iOS <a class="header-anchor" href="#ios" aria-label="Permalink to &quot;iOS&quot;">​</a></h3><p>To enable enhanced reporting for your iOS app campaigns with Google ICM through Branch, please confirm the following:</p><ul><li>You have an active iOS App campaign for installs with Google Ads.</li><li>You have implemented <a href="https://support.google.com/google-ads/answer/12119136" target="_blank" rel="noreferrer">on-device conversion measurement using event data</a> within your app.</li></ul><p>To benefit from ICM’s attribution coverage now, <strong>upgrade your infrastructure to ensure compatibility with ICM and future measurement improvements.</strong></p><p>To do this, you can:</p><ol><li>Upgrade to <a href="https://github.com/BranchMetrics/ios-branch-deep-linking-attribution/releases" target="_blank" rel="noreferrer">Branch iOS SDK (v3.13.3 or higher)</a> and integrate the standalone <a href="https://github.com/googleads/google-ads-on-device-conversion-ios-sdk" target="_blank" rel="noreferrer">On Device Conversion Measurement (ODM) SDK</a> from Google.</li><li>Upgrade to <a href="https://github.com/BranchMetrics/ios-branch-deep-linking-attribution/releases" target="_blank" rel="noreferrer">Branch iOS SDK (v3.13.3 or higher)</a> and upgrade your Firebase SDK to <a href="https://firebase.google.com/support/release-notes/ios#version_11140_-_june_3_2025" target="_blank" rel="noreferrer">v11.14.0</a>, which includes the ODM SDK.</li><li>Use a server-to-server integration, where you will need to pass the on-device measurement <code>”odm_info”</code> string to Branch.</li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>Google has reported that advertisers with a majority of logged-in users who implemented a similar solution with their first-party data saw a median 19% reduction in CPA on Google&#39;s owned inventory!</p></div><h3 id="android" tabindex="-1">Android <a class="header-anchor" href="#android" aria-label="Permalink to &quot;Android&quot;">​</a></h3><p>There are no immediate actions that you need to take in order to gain access to this solution for Android. Measurement improvements will automatically be applied when available.</p><h2 id="additional-resources" tabindex="-1">Additional resources <a class="header-anchor" href="#additional-resources" aria-label="Permalink to &quot;Additional resources&quot;">​</a></h2><p>To learn more about integrating Google Ads with Branch and leveraging its full capabilities, please refer to our <a href="https://help.branch.io/docs/google-ads-index" target="_blank" rel="noreferrer">comprehensive documentation</a>.</p><p>For more information about Google’s requirements for ICM, please refer to Google’s <a href="https://support.google.com/google-ads/answer/12119136?sjid=7730411304741579192-NC#:~:text=Implementation%20requirements%20to%20get%20started" target="_blank" rel="noreferrer">Integration Guide</a> and to your Google representative.</p><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>To analyze cross-channel attribution, considering coupling ICM with Branch’s <a href="./predictive-aggregate-measurement.html">Predictive Aggregate Measurement (PAM)</a>.</p><p>While ICM improves visibility into conversions under privacy constraints, PAM complements this by providing insights into previously unattributed conversions, offering a more comprehensive view of campaign performance.</p></div>',25)])])}const u=r(t,[["render",n]]);export{d as __pageData,u as default};
